#include<bits/stdc++.h>
using namespace std;
const long long N=1000000,mod=1e9+7;
long long jc[1000010],ny[1000010];
long long C(long long n,long long m)
{
    if(n<m)
    {
        return 0;
    }
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    jc[0]=ny[0]=1;
    for(long long i=1;i<=N;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[N]=fastpow(jc[N],mod-2);
    for(int i=N-1;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    long long n,m,q;
    scanf("%lld%lld%lld",&n,&m,&q);
    while(q--)
    {
        long long x,t;
        scanf("%lld%lld",&x,&t);
        long long a=(min(n,x+t)-t)-max(1ll,x-t)+1;
        long long b=n-t-a;
        long long c=(min(n-1,x+t-1)-(t-1))-max(2ll,x-(t-1))+1;
        long long d=n-t-1-c;
        printf("%lld\n",((a*C(t,m)%mod+b*C(t+1,m)%mod-c*C(t-1,m)%mod-d*C(t,m)%mod)%mod+mod)%mod*jc[m]%mod);
    }
    return 0;
}
